// Parse plan ONCE from subagent's first message
function parsePlanFromText(text: string): string[] {
    const steps: string[] = [];
    // Match "## Steps" section and extract "Step N: label" lines
    const match = text.match(/## Steps?\s*\n((?:Step \d+: .+\n?)+)/i);
    if (!match) return steps;

    const stepLines = match[1].matchAll(/Step\s+(\d+):\s*(.+)/gi);
    for (const [, , label] of stepLines) {
        steps.push(label.trim());
    }
    return steps;
}

// Handle text delta — only advances step, never creates new ones
function handleTextDelta(state: ActivityFeedState, text: string): ActivityFeedState {
    if (!state.planParsed) {
        // First message: extract plan once
        const planSteps = parsePlanFromText(text);
        if (planSteps.length > 0) {
            return {
                ...state,
                steps: planSteps.map(label => ({
                    label, completed: false, substeps: [],
                    startTime: Date.now()
                })),
                currentStep: 0,
                planParsed: true
            };
        }
        return state;
    }

    // Subsequent text: detect step transitions only
    // "Step 3:" → advance from step 2 to step 3
    const advance = text.match(/Step\s+(\d+):\s*(.+)/i);
    if (advance) {
        const stepNum = parseInt(advance[1]) - 1;  // 0-indexed
        while (state.currentStep < stepNum && state.currentStep < state.steps.length) {
            state = completeCurrentStep(state);    // marks ✓, advances
        }
    }

    return state;
}
