305 const MAX_RAW_TEXT = 10_000;
306 
307 export function parseTextForFeed(state: ActivityFeedState, text: string): ActivityFeedState {
308 	let rawText = state.rawText + text;
309 	if (rawText.length > MAX_RAW_TEXT) {
310 		const excess = rawText.length - MAX_RAW_TEXT;
311 		const firstNewline = rawText.indexOf("\n", excess);
312 		rawText = firstNewline >= 0 ? rawText.slice(firstNewline + 1) : rawText.slice(excess);
313 	}
314 
315 	const lines = rawText.split("\n");
316 	const completeLines = lines.slice(0, -1);
317 
318 	let currentState: ActivityFeedState = { ...state, rawText };
319 	let inGoalSection = false;
320 	let inStepsSection = false;
321 	const existingStepLabels = new Set(currentState.steps.map((s) => s.label));
322 
323 	for (const line of completeLines) {
324 		const trimmed = line.trim();
325 		if (!trimmed) {
326 			inGoalSection = false;
327 			inStepsSection = false;
328 			continue;
329 		}
330 
331 		// Detect ## Goal section
332 		if (trimmed.match(/^##\s+Goal/i)) {
333 			inGoalSection = true;
334 			inStepsSection = false;
335 			continue;
336 		}
337 
338 		// Detect ## Steps section
339 		if (trimmed.match(/^##\s+Steps/i)) {
340 			inStepsSection = true;
341 			inGoalSection = false;
342 			continue;
343 		}
344 
345 		// Any other ## header exits both
346 		if (trimmed.match(/^#{1,3}\s+/)) {
347 			inGoalSection = false;
348 			inStepsSection = false;
349 			continue;
350 		}
351 
352 		// Goal text (line after ## Goal)
353 		if (inGoalSection && currentState.goal === "") {
354 			currentState = { ...currentState, goal: trimmed };
355 			continue;
356 		}
357 
358 		// Steps section parsing
359 		if (inStepsSection) {
360 			// Canonical: Step N: <label>
361 			const stepMatch = trimmed.match(/^Step\s+(\d+):\s*(.+)/i);
362 			if (stepMatch) {
363 				resetSpinner();
364 				const stepLabel = stepMatch[2].trim();
365 				if (stepLabel && !existingStepLabels.has(stepLabel)) {
366 					currentState = addStep(currentState, stepLabel);
367 					existingStepLabels.add(stepLabel);
368 				}
369 				continue;
370 			}
371 
372 			// Indented bullet: substep of current step
373 			const indentMatch = line.match(/^(\s{2,})[-*]\s+(.+)/);
374 			if (indentMatch && currentState.currentStep >= 0 &&
375 					currentState.currentStep < currentState.steps.length) {
376 				const bulletText = indentMatch[2].trim();
377 				const isReport = /^Report:\s*(.+)/i.exec(bulletText);
378 				const substepLabel = isReport ? isReport[1].trim() : bulletText;
379 				const step = currentState.steps[currentState.currentStep];
380 
381 				if (!step.substeps.some((s) => s.label === substepLabel)) {
382 					// Report bullets are completed findings; regular bullets are pending actions
383 					const newSubstep: Substep = {
384 						label: substepLabel,
385 						completed: !!isReport,
386 						isReport: !!isReport,
387 						startTime: Date.now(),
388 						endTime: isReport ? Date.now() : undefined,
389 					};
390 					const newSubsteps = [...step.substeps, newSubstep];
391 					const newSteps = currentState.steps.map((s, i) =>
392 						i === currentState.currentStep ? { ...s, substeps: newSubsteps } : s
393 					);
394 					currentState = { ...currentState, steps: newSteps };
395 				}
396 				continue;
397 			}
398 
399 			// Backward compat: non-indented - bullet treated as step label
400 			const legacyBullet = trimmed.match(/^[-*]\s+(.+)/);
401 			if (legacyBullet) {
402 				const label = legacyBullet[1].trim();
403 				if (!label.match(/^Report:/i) && !existingStepLabels.has(label)) {
404 					currentState = addStep(currentState, label);
405 					existingStepLabels.add(label);
406 				}
407 				continue;
408 			}
409 
410 			// Backward compat: numbered "1. <label>" or "1) <label>"
411 			const numMatch = trimmed.match(/^\d+[.)]\s+(.+)/);
412 			if (numMatch) {
413 				const label = numMatch[1].trim();
414 				if (!existingStepLabels.has(label)) {
415 					currentState = addStep(currentState, label);
416 					existingStepLabels.add(label);
417 				}
418 				continue;
419 			}
420 
421 			continue;
422 		}
423 
424 		// Fallback: first non-header line before any section is the goal
425 		if (currentState.goal === "" && !trimmed.startsWith("#")) {
426 			currentState = { ...currentState, goal: trimmed };
427 		}
428 	}
429 
430 	return currentState;
431 }
