433 export function addStep(state: ActivityFeedState, label: string): ActivityFeedState {
434 	if (label === "Working...") return state;
435 
436 	for (let i = 0; i < state.steps.length; i++) {
437 		const existing = state.steps[i];
438 		if (label.startsWith(existing.label) && label.length > existing.label.length
439 			&& existing.substeps.length === 0 && !existing.completed) {
440 			const newSteps = state.steps.map((s, idx) => idx === i ? { label, completed: false, substeps: [], startTime: existing.startTime } : s);
441 			return { ...state, steps: newSteps };
442 		}
443 	}
444 
445 	if (state.steps.some((s) => s.label === label)) return state;
446 
447 	let steps = state.steps;
448 	let currentStep = state.currentStep;
449 	if (state.steps.length >= MAX_FEED_STEPS) {
450 		steps = state.steps.slice(1);
451 		if (currentStep > 0) currentStep--;
452 	}
453 	steps = [...steps, { label, completed: false, substeps: [], startTime: Date.now() }];
454 	if (currentStep === -1) currentStep = 0;
455 	return { ...state, steps, currentStep };
456 }
457 
458 export function addSubstep(state: ActivityFeedState, label: string): ActivityFeedState {
459 	let { steps, currentStep } = state;
460 
461 	if (currentStep >= 0 && currentStep < steps.length && steps[currentStep].completed) {
462 		return addStep(state, label);
463 	}
464 	if (currentStep < 0 || steps.length === 0) {
465 		if (steps.length === 0) {
466 			const stepLabel = label.length > 60 ? label.slice(0, 57) + "..." : label;
467 			return {
468 				...state,
469 				steps: [{ label: stepLabel, completed: false, substeps: [{ label, completed: false, startTime: Date.now() }], startTime: Date.now() }],
470 				currentStep: 0,
471 			};
472 		}
473 	}
474 	if (currentStep < 0 || currentStep >= steps.length) {
475 		return addStep(state, label);
476 	}
477 
478 	const step = steps[currentStep];
479 	if (step.substeps.some((s) => s.label === label)) return state;
480 
481 	let newSubsteps = step.substeps;
482 	if (step.substeps.length >= MAX_FEED_SUBSTEPS) {
483 		newSubsteps = step.substeps.slice(1);
484 	}
485 	newSubsteps = [...newSubsteps, { label, completed: false, startTime: Date.now() }];
486 
487 	const newSteps = steps.map((s, i) => i === currentStep ? { ...s, substeps: newSubsteps } : s);
488 	return { ...state, steps: newSteps };
489 }
