491 /**
492  * Complete the active (first uncompleted) substep of the current step.
493  * In the new model, substeps are parsed upfront in order; the first uncompleted is the active one.
494  */
495 export function completeLastSubstep(state: ActivityFeedState, outputPreview?: string): ActivityFeedState {
496 	if (state.currentStep < 0 || state.currentStep >= state.steps.length) return state;
497 	const step = state.steps[state.currentStep];
498 	if (step.substeps.length === 0) return state;
499 
500 	// Find first uncompleted substep (the active one)
501 	let activeIdx = -1;
502 	for (let i = 0; i < step.substeps.length; i++) {
503 		if (!step.substeps[i].completed) {
504 			activeIdx = i;
505 			break;
506 		}
507 	}
508 	if (activeIdx < 0) return state;
509 
510 	const now = Date.now();
511 	const newSubsteps = step.substeps.map((sub, i) => {
512 		if (i !== activeIdx) return sub;
513 		return { ...sub, completed: true, endTime: now, ...(outputPreview ? { outputPreview } : {}) };
514 	});
515 	const newSteps = state.steps.map((s, i) => i === state.currentStep ? { ...s, substeps: newSubsteps } : s);
516 	return { ...state, steps: newSteps };
517 }
