### How to register tools with AgentSession

**Option 1: `customTools` on `createAgentSession()`** (programmatic, no extension)

```typescript
import { createAgentSession, defineTool } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";

const myTool = defineTool({
    name: "my_tool",
    label: "My Tool",
    description: "Does something useful",
    parameters: Type.Object({
        input: Type.String({ description: "Input value" }),
    }),
    execute: async (_toolCallId, params, signal, onUpdate, ctx) => ({
        content: [{ type: "text", text: `Result: ${params.input}` }],
        details: {},
    }),
});

const { session } = await createAgentSession({
    customTools: [myTool],
    tools: ["read", "bash", "my_tool"],  // must explicitly enable
});
```

**Option 2: `pi.registerTool()` inside an extension**

```typescript
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";

export default function (pi: ExtensionAPI) {
    pi.registerTool({
        name: "greet",
        label: "Greet",
        description: "Greet someone by name",
        parameters: Type.Object({
            name: Type.String({ description: "Name to greet" }),
        }),
        async execute(toolCallId, params, signal, onUpdate, ctx) {
            return {
                content: [{ type: "text", text: `Hello, ${params.name}!` }],
                details: {},
            };
        },
    });
}
```

Then either pass via `customTools` or use `ResourceLoader` with extension paths.

