```typescript
import timeline from "/private/tmp/orchestrator-timeline-mqfumcmmqgasn0.json" assert { type: "json" };

test("timeline replay: step progression is monotonic", () => {
    let feed = createActivityFeed();

    for (const frame of timeline.events) {
        // Replay each event through the feed state machine
        switch (frame.event) {
            case "step_started":
                // parse step labels from frame data
                break;
            case "tool_start":
                feed = addSubstep(feed, frame.toolLabel);
                break;
            case "tool_end":
                feed = completeLastSubstep(feed);
                break;
            case "step_completed":
                feed = completeCurrentStep(feed);
                break;
