  /** Description for LLM */
  description: string;
  /** Optional one-line snippet for the Available tools section */
  promptSnippet?: string;
  /** Optional guideline bullets appended to default system prompt */
  promptGuidelines?: string[];
  /** Parameter schema (TypeBox) */
  parameters: TParams;
  /** Controls rendering shell */
  renderShell?: "default" | "self";
  /** Prepare raw args before schema validation */
  prepareArguments?: (args: unknown) => Static<TParams>;
  /** Execution mode: "sequential" | "parallel" */
  executionMode?: ToolExecutionMode;
  /** Execute the tool */
  execute(
    toolCallId: string,
    params: Static<TParams>,
    signal: AbortSignal | undefined,
    onUpdate: AgentToolUpdateCallback<TDetails> | undefined,
    ctx: ExtensionContext
  ): Promise<AgentToolResult<TDetails>>;
  /** Custom render for tool call display */
  renderCall?: (...args) => Component;
  /** Custom render for tool result display */
  renderResult?: (...args) => Component;
}
```

Parameters must use **TypeBox** `Type.Object({...})` schema (not raw JSON Schema).

### 3. `defineTool` — function signature

**File:** `dist/core/extensions/types.d.ts` (same file, right after `ToolDefinition`)

```typescript
export declare function defineTool<
  TParams extends TSchema,
  TDetails = unknown,
  TState = any
>(
  tool: ToolDefinition<TParams, TDetails, TState>
): ToolDefinition<TParams, TDetails, TState> & AnyToolDefinition;
```

Purpose: Preserves parameter inference when assigning a tool to a variable or passing through arrays like `customTools`. Without it, contextual typing would widen `params` to `unknown`.

### 4. SDK docs — usage example

**File:** `docs/sdk.md`

```typescript
import { Type } from "typebox";
import { createAgentSession, defineTool } from "@earendil-works/pi-coding-agent";

// Inline custom tool
const myTool = defineTool({
  name: "my_tool",
  label: "My Tool",
  description: "Does something useful",
  parameters: Type.Object({
    input: Type.String({ description: "Input value" }),
  }),
  execute: async (_toolCallId, params) => ({
    content: [{ type: "text", text: `Result: ${params.input}` }],
    details: {},
  }),
});

// Pass custom tools directly
const { session } = await createAgentSession({
  customTools: [myTool],
});
```

Custom tools are combined with extension-registered tools. If using `tools` allowlist, include custom tool names: `tools: ["read", "bash", "my_tool"]`.

