Add import: `import { join, isAbsolute, resolve, dirname, parse } from "node:path";` (update path imports)

### 2. Add detectTool() function — language-based tool selection

This replaces the old detectLinter() approach. Instead of checking configs first, detect the language from extension and select the appropriate tool:

```typescript
interface LintTool {
    tool: string;
    args: string[];
    cwd?: string;
    name: string;  // display name like "tsc", "ruff", "go vet"
}

function detectTool(filePath: string, cwd: string): LintTool | null {
    const ext = filePath.split('.').pop()?.toLowerCase();

    // Walk up for project config
    const config = walkUpForConfig(filePath, [
        "tsconfig.json", "biome.json", "biome.jsonc",
        "eslint.config.js", "eslint.config.mjs",
        "pyproject.toml", "ruff.toml",
        "go.mod", "Cargo.toml",
        "pom.xml", "build.gradle", "build.gradle.kts",
        ".rubocop.yml"
    ]);

    switch (ext) {
        case "ts":
        case "tsx":
            if (config?.name === "tsconfig.json" || config?.name === "biome.json" || config?.name === "biome.jsonc") {
                // Use tsconfig from project root
                return { tool: "npx", args: ["tsc", "--noEmit", "--incremental"], cwd: config.dir, name: "tsc" };
            }
            if (config?.name?.startsWith("eslint")) {
                return { tool: "npx", args: ["eslint", filePath, "--no-error-on-unmatched-pattern"], name: "eslint" };
            }
            // Standalone: no config needed
            return { tool: "npx", args: ["tsc", "--noEmit", "--strict", filePath], name: "tsc" };

        case "js":
        case "jsx":
        case "mjs":
            if (config?.name === "tsconfig.json") {
                return { tool: "npx", args: ["tsc", "--allowJs", "--checkJs", "--noEmit"], cwd: config.dir, name: "tsc" };
            }
            if (config?.name?.startsWith("eslint")) {
                return { tool: "npx", args: ["eslint", filePath, "--no-error-on-unmatched-pattern"], name: "eslint" };
            }
            // Standalone: node --check
            return { tool: "node", args: ["--check", filePath], name: "node" };

        case "py":
            if (config?.name === "ruff.toml" || config?.name === "pyproject.toml") {
                return { tool: "ruff", args: ["check", filePath], name: "ruff" };
            }
            // Standalone: ruff works zero-config
            return { tool: "ruff", args: ["check", filePath], name: "ruff" };

        case "go":
            // Go always has go.mod in real projects
            if (config?.name === "go.mod") {
                return { tool: "go", args: ["vet", "./..."], cwd: config.dir, name: "go vet" };
            }
            return null;  // No standalone Go check

        case "rs":
            if (config?.name === "Cargo.toml") {
                return { tool: "cargo", args: ["check"], cwd: config.dir, name: "cargo" };
            }
            return null;

        case "java":
            if (config?.name === "pom.xml") {
                return { tool: "mvn", args: ["compile", "-q"], cwd: config.dir, name: "mvn" };
            }
            if (config?.name === "build.gradle" || config?.name === "build.gradle.kts") {
                return { tool: "./gradlew", args: ["compileJava", "--quiet"], cwd: config.dir, name: "gradle" };
            }
            // Standalone: javac single file
            return { tool: "javac", args: ["-Xlint:all", filePath], name: "javac" };

        case "rb":
            if (config?.name === ".rubocop.yml") {
                return { tool: "rubocop", args: [filePath], name: "rubocop" };
            }
            // Standalone: ruby -c
            return { tool: "ruby", args: ["-c", filePath], name: "ruby" };

        default:
            return null;
    }
}
```

### 3. Add runTool() function — executes the tool and returns result

```typescript
interface LintResult {
    success: boolean;
    errors: string;
    tool: string;
    file: string;
}

function runTool(tool: LintTool, filePath: string): Promise<LintResult> {
    return new Promise((resolve) => {
        const startTime = Date.now();
        const child = spawn(tool.tool, tool.args, {
            cwd: tool.cwd || process.cwd(),
            stdio: ["ignore", "pipe", "pipe"],
            timeout: 10_000,  // 10s timeout
        });

        let stdout = "";
        let stderr = "";

        child.stdout.on("data", (data) => { stdout += data.toString(); });
        child.stderr.on("data", (data) => { stderr += data.toString(); });

        child.on("close", (code) => {
            const elapsed = Date.now() - startTime;
            const output = (stdout + stderr).trim();
            const success = code === 0;

            resolve({
                success,
                errors: success ? "" : output.slice(0, 2000),  // cap at 2k chars
                tool: tool.name,
                file: filePath,
            });
        });

        child.on("error", (err) => {
            resolve({
                success: false,
                errors: `Tool not available: ${err.message}`,
                tool: tool.name,
                file: filePath,
            });
        });
    });
}
```

